    settled_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    remark text,
    CONSTRAINT ck_settlement_actual CHECK ((actual_amount >= (0)::numeric)),
    CONSTRAINT ck_settlement_amount CHECK ((total_amount >= (0)::numeric))
);


ALTER TABLE public.wage_settlements OWNER TO salary;

--
-- Name: v_project_user_settlement_status; Type: VIEW; Schema: public; Owner: salary
--

CREATE VIEW public.v_project_user_settlement_status AS
 SELECT COALESCE((pus.id)::bigint, row_number() OVER (ORDER BY p.id, u.id)) AS id,
    p.id AS project_id,
    u.id AS user_id,
    COALESCE(pus.settlement_status, (
        CASE
            WHEN (ws.id IS NOT NULL) THEN 'settled'::text
            WHEN ((p.status)::text = 'completed'::text) THEN 'settling'::text
            WHEN (EXISTS ( SELECT 1
               FROM public.subprojects sp
              WHERE ((sp.project_id = p.id) AND ((sp.status)::text = 'completed'::text)))) THEN 'settling'::text
            ELSE 'unsettled'::text
        END)::character varying) AS settlement_status,
    COALESCE(pus.settlement_id, ws.id) AS settlement_id,
    COALESCE(pus.settled_at, ws.settled_at) AS settled_at,
    COALESCE(pus.created_at, CURRENT_TIMESTAMP) AS created_at,
    COALESCE(pus.updated_at, CURRENT_TIMESTAMP) AS updated_at
   FROM ((((public.projects p
     JOIN public.project_workers pw ON ((pw.project_id = p.id)))
     JOIN public.users u ON ((u.id = pw.user_id)))
     LEFT JOIN public.project_user_status pus ON (((pus.project_id = p.id) AND (pus.user_id = u.id))))
     LEFT JOIN public.wage_settlements ws ON (((ws.user_id = u.id) AND ((ws.project_id = p.id) OR (ws.project_ids @> to_jsonb(p.id))))))
UNION
 SELECT COALESCE((pus.id)::bigint, (row_number() OVER (ORDER BY p.id, u.id) + 100000)) AS id,
    p.id AS project_id,
    u.id AS user_id,
    COALESCE(pus.settlement_status, 'unsettled'::character varying) AS settlement_status,
    pus.settlement_id,
    pus.settled_at,
    COALESCE(pus.created_at, CURRENT_TIMESTAMP) AS created_at,
    COALESCE(pus.updated_at, CURRENT_TIMESTAMP) AS updated_at
   FROM ((public.projects p
     CROSS JOIN public.users u)
     LEFT JOIN public.project_user_status pus ON (((pus.project_id = p.id) AND (pus.user_id = u.id))))
  WHERE ((u.role)::text = ANY ((ARRAY['admin'::character varying, 'documenter'::character varying])::text[]));


ALTER VIEW public.v_project_user_settlement_status OWNER TO salary;

